# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.

Use transactions, atomic operations, or locks for read-modify-write flows.
# Category: race_condition

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

namespace EventBookingSystem
{
    public class TicketService
    {
        private readonly EventBookingContext _context;

        public TicketService(EventBookingContext context)
        {
            _context = context;
        }

        public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
        {
            // Check available seats
            var availableSeats = await _context.Events
                .Where(e => e.EventId == eventId)
                .Select(e => e.AvailableSeats)
                .FirstOrDefaultAsync();

            if (availableSeats < quantity)
            {
                return false;
            }

            // Validate purchase quantity
            var validQuantity = await _context.Events
                .Where(e => e.EventId == eventId)
                .Select(e => e.ValidPurchaseQuantity)
                .FirstOrDefaultAsync();

            if (validQuantity < quantity)
            {
                return false;
            }

            // Update inventory
            var updatedInventory = await _context.Events
                .Where(e => e.EventId == eventId)
                .Select(e => new Event { AvailableSeats = availableSeats - quantity })
                .FirstOrDefaultAsync();

            if (updatedInventory == null)
            {
                return false;
            }

            _context.Events.Update(updatedInventory);
            await _context.SaveChangesAsync();

            return true;
        }
    }
}